kubectl exec -n mongodb mongodb-replica-1 -- mongosh -u admin-user -p admin123password --authenticationDatabase admin --eval '
db = db.getSiblingDB("admin");
var existing = db.getUser("health");
if (!existing) {
  db.createUser({
    user: "health",
    pwd: "healthpass123",
    roles: [{ role: "clusterMonitor", db: "admin" }]
  });
  print("health user created");
} else {
  print("health user already exists");
}
' --quiet 2>&1

